import { useEffect, useState } from "react";
import ClientLayout from "../../components/layout/ClientLayout";
import axiosClient from "../../api/axiosClient";
import "../../styles/client/ProfilePage.css";

/* ── Avatar with initials ── */
function Avatar({ name = "", size = 80 }) {
  const initials = name
    .split(" ")
    .slice(0, 2)
    .map((w) => w[0] || "")
    .join("")
    .toUpperCase() || "?";

  return (
    <div className="profile-avatar" style={{ width: size, height: size, fontSize: size * 0.36 }}>
      {initials}
    </div>
  );
}

/* ── Input field ── */
function Field({ label, icon, value, onChange, type = "text", disabled = false, placeholder = "" }) {
  return (
    <div className="pf-field">
      <label className="pf-label">{label}</label>
      <div className="pf-input-wrap">
        <i className={`bx ${icon} pf-input-icon`} />
        <input
          className="pf-input"
          type={type}
          value={value || ""}
          onChange={(e) => onChange(e.target.value)}
          disabled={disabled}
          placeholder={placeholder}
        />
      </div>
    </div>
  );
}

/* ── Main ── */
export default function ProfilePage() {
  const [profile,  setProfile]  = useState(null);
  const [loading,  setLoading]  = useState(true);
  const [saving,   setSaving]   = useState(false);
  const [tab,      setTab]      = useState("info"); // info | security | stats
  const [success,  setSuccess]  = useState("");
  const [error,    setError]    = useState("");

  /* Edit form state */
  const [form, setForm] = useState({
    fullName:    "",
    phone:       "",
    companyName: "",
    contactPerson: "",
    notes:       "",
  });

  /* Password form */
  const [pwForm, setPwForm] = useState({
    currentPassword: "",
    newPassword:     "",
    confirmPassword: "",
  });

  const [stats, setStats] = useState({
    total: 0, delivered: 0, cancelled: 0, inProgress: 0,
  });

  /* Load profile */
  useEffect(() => {
    (async () => {
      try {
        const res = await axiosClient.get("/client/profile");
        const d   = res.data;
        setProfile(d);
        setForm({
          fullName:      d.fullName      || "",
          phone:         d.phone         || "",
          companyName:   d.companyName   || "",
          contactPerson: d.contactPerson || "",
          notes:         d.notes        || "",
        });
      } catch {
        setError("Не удалось загрузить профиль");
      } finally {
        setLoading(false);
      }
    })();
  }, []);

  /* Load order stats */
  useEffect(() => {
    (async () => {
      try {
        const res  = await axiosClient.get("/client/orders");
        const list = Array.isArray(res.data) ? res.data : res.data.content || [];
        setStats({
          total:      list.length,
          delivered:  list.filter(o => o.status === "Доставлен").length,
          cancelled:  list.filter(o => o.status === "Отменён").length,
          inProgress: list.filter(o => ["Назначен","В процессе"].includes(o.status)).length,
        });
      } catch {}
    })();
  }, []);

  const set  = (k, v) => setForm(p => ({ ...p, [k]: v }));
  const setPw = (k, v) => setPwForm(p => ({ ...p, [k]: v }));

  const flash = (type, msg) => {
    if (type === "ok") { setSuccess(msg); setError(""); }
    else               { setError(msg);   setSuccess(""); }
    setTimeout(() => { setSuccess(""); setError(""); }, 4000);
  };

  /* Save profile */
  const handleSave = async () => {
    setSaving(true);
    try {
      await axiosClient.put("/client/profile", form);
      setProfile(p => ({ ...p, ...form }));
      flash("ok", "Профиль успешно обновлён");
    } catch {
      flash("err", "Ошибка при сохранении профиля");
    } finally {
      setSaving(false);
    }
  };

  /* Change password */
  const handlePassword = async () => {
    if (pwForm.newPassword !== pwForm.confirmPassword) {
      flash("err", "Пароли не совпадают"); return;
    }
    if (pwForm.newPassword.length < 6) {
      flash("err", "Пароль должен быть не менее 6 символов"); return;
    }
    setSaving(true);
    try {
      await axiosClient.post("/client/profile/change-password", {
        currentPassword: pwForm.currentPassword,
        newPassword:     pwForm.newPassword,
      });
      setPwForm({ currentPassword: "", newPassword: "", confirmPassword: "" });
      flash("ok", "Пароль успешно изменён");
    } catch {
      flash("err", "Неверный текущий пароль");
    } finally {
      setSaving(false);
    }
  };

  if (loading) return (
    <ClientLayout>
      <div className="profile-root">
        <div className="profile-skels">
          {[1,2,3].map(i => <div key={i} className="profile-skel" />)}
        </div>
      </div>
    </ClientLayout>
  );

  return (
    <ClientLayout>
      <div className="profile-root">

        {/* ── HERO ── */}
        <div className="profile-hero">
          <div className="profile-hero-left">
            <Avatar name={profile?.fullName || ""} size={72} />
            <div className="profile-hero-info">
              <h1 className="profile-name">{profile?.fullName || "—"}</h1>
              <div className="profile-email">
                <i className="bx bx-envelope" /> {profile?.email || "—"}
              </div>
              <div className="profile-role-badge">
                <i className="bx bx-user-circle" /> Клиент
              </div>
            </div>
          </div>
          <div className="profile-hero-meta">
            <div className="profile-meta-item">
              <i className="bx bx-calendar" />
              <span>Зарегистрирован</span>
              <strong>
                {profile?.createdAt
                  ? new Date(profile.createdAt).toLocaleDateString("ru-RU", { day:"numeric", month:"long", year:"numeric" })
                  : "—"}
              </strong>
            </div>
            <div className={`profile-status-badge ${profile?.status === "Активен" ? "profile-status-badge--active" : "profile-status-badge--blocked"}`}>
              <span className="profile-status-dot" />
              {profile?.status || "—"}
            </div>
          </div>
        </div>

        {/* ── FLASH ── */}
        {success && (
          <div className="profile-flash profile-flash--ok">
            <i className="bx bx-check-circle" /> {success}
          </div>
        )}
        {error && (
          <div className="profile-flash profile-flash--err">
            <i className="bx bx-error-circle" /> {error}
          </div>
        )}

        {/* ── TABS ── */}
        <div className="profile-tabs">
          {[
            { id: "info",     icon: "bx-user",       label: "Личные данные"  },
            { id: "security", icon: "bx-lock-alt",   label: "Безопасность"   },
            { id: "stats",    icon: "bx-bar-chart-alt-2", label: "Статистика" },
          ].map(t => (
            <button
              key={t.id}
              className={`profile-tab ${tab === t.id ? "profile-tab--active" : ""}`}
              onClick={() => setTab(t.id)}
            >
              <i className={`bx ${t.icon}`} /> {t.label}
            </button>
          ))}
        </div>

        {/* ── TAB: INFO ── */}
        {tab === "info" && (
          <div className="profile-grid">

            {/* Personal */}
            <div className="profile-card">
              <div className="profile-card-title">
                <i className="bx bx-user" /> Личная информация
              </div>
              <Field
                label="ФИО"
                icon="bx-id-card"
                value={form.fullName}
                onChange={v => set("fullName", v)}
                placeholder="Иванов Иван Иванович"
              />
              <Field
                label="Email"
                icon="bx-envelope"
                value={profile?.email}
                onChange={() => {}}
                disabled
              />
              <Field
                label="Телефон"
                icon="bx-phone"
                value={form.phone}
                onChange={v => set("phone", v)}
                placeholder="+7 (999) 999-99-99"
              />
              <div className="profile-oauth">
                {profile?.oauthProvider && (
                  <div className="profile-oauth-badge">
                    <i className="bx bxl-google" /> Аккаунт Google привязан
                  </div>
                )}
              </div>
            </div>

            {/* Company */}
            <div className="profile-card">
              <div className="profile-card-title">
                <i className="bx bx-building" /> Данные компании
              </div>
              <Field
                label="Название компании"
                icon="bx-building-house"
                value={form.companyName}
                onChange={v => set("companyName", v)}
                placeholder="ООО «Ромашка»"
              />
              <Field
                label="Контактное лицо"
                icon="bx-user-pin"
                value={form.contactPerson}
                onChange={v => set("contactPerson", v)}
                placeholder="Менеджер по логистике"
              />
              <div className="pf-field">
                <label className="pf-label">Примечания</label>
                <textarea
                  className="pf-input pf-textarea"
                  value={form.notes}
                  onChange={e => set("notes", e.target.value)}
                  placeholder="Дополнительная информация..."
                />
              </div>

              <button
                className="profile-save-btn"
                onClick={handleSave}
                disabled={saving}
              >
                <i className="bx bx-save" />
                {saving ? "Сохраняем..." : "Сохранить изменения"}
              </button>
            </div>

          </div>
        )}

        {/* ── TAB: SECURITY ── */}
        {tab === "security" && (
          <div className="profile-grid profile-grid--single">
            <div className="profile-card">
              <div className="profile-card-title">
                <i className="bx bx-lock-alt" /> Изменить пароль
              </div>

              <div className="pf-field">
                <label className="pf-label">Текущий пароль</label>
                <div className="pf-input-wrap">
                  <i className="bx bx-lock pf-input-icon" />
                  <input
                    className="pf-input"
                    type="password"
                    value={pwForm.currentPassword}
                    onChange={e => setPw("currentPassword", e.target.value)}
                    placeholder="••••••••"
                  />
                </div>
              </div>

              <div className="pf-field">
                <label className="pf-label">Новый пароль</label>
                <div className="pf-input-wrap">
                  <i className="bx bx-key pf-input-icon" />
                  <input
                    className="pf-input"
                    type="password"
                    value={pwForm.newPassword}
                    onChange={e => setPw("newPassword", e.target.value)}
                    placeholder="Минимум 6 символов"
                  />
                </div>
              </div>

              <div className="pf-field">
                <label className="pf-label">Подтвердите пароль</label>
                <div className="pf-input-wrap">
                  <i className="bx bx-check-shield pf-input-icon" />
                  <input
                    className="pf-input"
                    type="password"
                    value={pwForm.confirmPassword}
                    onChange={e => setPw("confirmPassword", e.target.value)}
                    placeholder="Повторите новый пароль"
                  />
                </div>
              </div>

              {/* Password strength */}
              {pwForm.newPassword && (
                <PasswordStrength password={pwForm.newPassword} />
              )}

              <button
                className="profile-save-btn"
                onClick={handlePassword}
                disabled={saving || !pwForm.currentPassword || !pwForm.newPassword}
              >
                <i className="bx bx-shield-alt-2" />
                {saving ? "Обновляем..." : "Обновить пароль"}
              </button>
            </div>

            {/* Security info */}
            <div className="profile-card profile-card--info">
              <div className="profile-card-title">
                <i className="bx bx-info-circle" /> Рекомендации
              </div>
              <div className="profile-tips">
                {[
                  { icon: "bx-check",        text: "Используйте не менее 8 символов"          },
                  { icon: "bx-check",        text: "Добавьте цифры и специальные символы"      },
                  { icon: "bx-check",        text: "Не используйте один пароль для всех сайтов"},
                  { icon: "bx-check",        text: "Меняйте пароль каждые 3–6 месяцев"         },
                ].map((tip, i) => (
                  <div key={i} className="profile-tip">
                    <i className={`bx ${tip.icon}`} /> {tip.text}
                  </div>
                ))}
              </div>
            </div>
          </div>
        )}

        {/* ── TAB: STATS ── */}
        {tab === "stats" && (
          <div className="profile-stats-tab">
            <div className="profile-stats-grid">
              {[
                { icon: "bx-package",       label: "Всего заказов",  num: stats.total,      cls: "ps-blue"   },
                { icon: "bx-check-circle",  label: "Доставлено",     num: stats.delivered,  cls: "ps-green"  },
                { icon: "bx-time-five",     label: "В пути сейчас",  num: stats.inProgress, cls: "ps-amber"  },
                { icon: "bx-x-circle",      label: "Отменено",       num: stats.cancelled,  cls: "ps-red"    },
              ].map(s => (
                <div key={s.label} className={`profile-stat-card ${s.cls}`}>
                  <i className={`bx ${s.icon} profile-stat-icon`} />
                  <div className="profile-stat-num">{s.num}</div>
                  <div className="profile-stat-label">{s.label}</div>
                </div>
              ))}
            </div>

            {/* Delivery rate */}
            {stats.total > 0 && (
              <div className="profile-card profile-rate-card">
                <div className="profile-card-title">
                  <i className="bx bx-trending-up" /> Процент успешных доставок
                </div>
                <div className="profile-rate-wrap">
                  <div className="profile-rate-num">
                    {Math.round((stats.delivered / stats.total) * 100)}%
                  </div>
                  <div className="profile-rate-bar-bg">
                    <div
                      className="profile-rate-bar-fill"
                      style={{ width: `${(stats.delivered / stats.total) * 100}%` }}
                    />
                  </div>
                  <div className="profile-rate-label">
                    {stats.delivered} из {stats.total} заказов доставлено успешно
                  </div>
                </div>
              </div>
            )}
          </div>
        )}

      </div>
    </ClientLayout>
  );
}

/* ── Password strength indicator ── */
function PasswordStrength({ password }) {
  const score =
    (password.length >= 8 ? 1 : 0) +
    (/[A-Z]/.test(password) ? 1 : 0) +
    (/[0-9]/.test(password) ? 1 : 0) +
    (/[^A-Za-z0-9]/.test(password) ? 1 : 0);

  const labels = ["Очень слабый", "Слабый", "Средний", "Сильный", "Очень сильный"];
  const colors = ["#ef4444", "#f97316", "#eab308", "#22c55e", "#16a34a"];

  return (
    <div className="pw-strength">
      <div className="pw-strength-bars">
        {[0,1,2,3].map(i => (
          <div
            key={i}
            className="pw-strength-bar"
            style={{ background: i < score ? colors[score] : "#e2e8f0" }}
          />
        ))}
      </div>
      <span className="pw-strength-label" style={{ color: colors[score] }}>
        {labels[score]}
      </span>
    </div>
  );
}
